+    #[test]
+    fn base_connector_repeated_set_configured_idempotent() {
+        let base = BaseConnector::new(test_connector_id());
+        base.set_configured(true);
+        base.set_configured(true);
+        base.set_configured(true);
+        assert!(base.configured.load(Ordering::Relaxed));
+
+        base.set_configured(false);
+        base.set_configured(false);
+        assert!(!base.configured.load(Ordering::Relaxed));
