+
+    #[test]
+    fn base_connector_repeated_set_handshaken_idempotent() {
+        let base = BaseConnector::new(test_connector_id());
+        base.set_handshaken(true);
+        base.set_handshaken(true);
+        assert!(base.handshaken.load(Ordering::Relaxed));
+
+        base.set_handshaken(false);
+        base.set_handshaken(false);
